export async function fetchRepos(repoNames: string[]): Promise<GitHubRepo[]> {
  if (!IS_DEV) {
    return apiFetch(`/api/github/repos?names=${repoNames.join(",")}`);
  }

  const results = await Promise.allSettled(
    repoNames.map((name) =>
      githubFetch<GitHubRepo>(`/repos/${GITHUB_USERNAME}/${name}`),
    ),
  );
  return results
    .filter((r): r is PromiseFulfilledResult<GitHubRepo> => r.status === "fulfilled")
    .map((r) => r.value);
}

interface SearchCommitsResponse {
  items: Array<{
    sha: string;
    html_url: string;
    commit: { message: string; author: { date: string } };
    repository: { name: string; full_name: string };
  }>;
}

interface CommitDetail {
  sha: string;
  stats: { additions: number; deletions: number };
}

export async function fetchRecentCommits(limit = 5): Promise<CommitActivity[]> {
  if (!IS_DEV) {
    return apiFetch(`/api/github/commits?limit=${limit}`);
  }

  const data = await githubFetch<SearchCommitsResponse>(
    `/search/commits?q=author:${GITHUB_USERNAME}&sort=author-date&order=desc&per_page=${limit}`,
  );

  const details = await Promise.allSettled(
    data.items.map((item) =>
      githubFetch<CommitDetail>(`/repos/${item.repository.full_name}/commits/${item.sha}`),
    ),
  );

  return data.items.map((item, i) => {
    const detail = details[i].status === "fulfilled" ? details[i].value : null;
    return {
      message: item.commit.message,
      repoName: item.repository.name,
      timestamp: item.commit.author.date,
      commitUrl: item.html_url,
      additions: detail?.stats.additions ?? 0,
      deletions: detail?.stats.deletions ?? 0,
    };
  });
}

