@import "tailwindcss";

@theme {
  --font-serif: "DM Serif Display", serif;
  --font-sans: "Geist Sans", system-ui, sans-serif;
  --font-mono: "Geist Mono", ui-monospace, monospace;

  --color-primary: #977ed4;
  --color-secondary: #cdc4ec;
  --color-accent: #cdc4ec;
  --color-bg: #161617;
  --color-surface: #1e1e20;
  --color-surface-2: #2a2a2d;
  --color-edge: #2e2e32;
  --color-content: #e4e4e7;
  --color-muted: #a1a1aa;
  --color-faint: #71717a;

  --max-width-container: 1100px;

  --animate-fade-up: fade-up 0.5s ease-out both;
  --animate-fade-in: fade-in 0.3s ease-out both;
  --animate-zoom-in: zoom-in 0.3s ease-out both;
  --animate-shimmer: shimmer 2s linear infinite;

  @keyframes fade-up {
    from {
      opacity: 0;
      transform: translateY(12px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }
  @keyframes fade-in {
    from {
      opacity: 0;
    }
    to {
      opacity: 1;
    }
  }
  @keyframes zoom-in {
    from {
      opacity: 0;
      transform: scale(0.95);
    }
    to {
      opacity: 1;
      transform: scale(1);
    }
  }
  @keyframes shimmer {
    0% {
      background-position: -200% 0;
    }
    100% {
      background-position: 200% 0;
    }
  }
}

@font-face {
  font-family: "Geist Sans";
  font-style: normal;
  font-weight: 100 900;
  font-display: swap;
  src: url("/fonts/GeistSansVariable.woff2") format("woff2");
}

@font-face {
  font-family: "Geist Mono";
  font-style: normal;
  font-weight: 100 900;
  font-display: swap;
  src: url("/fonts/GeistMonoVariable.woff2") format("woff2");
}

@layer base {
  :root {
    --color-primary: #977ed4;
