    --color-faint: #71717a;
  }

  :root[data-theme="light"] {
    --color-primary: #977ed4;
    --color-secondary: #51387a;
    --color-accent: #977ed4;
    --color-bg: #ffffff;
    --color-surface: #f5f5f5;
    --color-surface-2: #e8e8e8;
    --color-edge: #e0e0e0;
    --color-content: #18181b;
    --color-muted: #71717a;
    --color-faint: #a1a1aa;
  }

  html {
    scroll-behavior: smooth;
  }

  body {
    @apply bg-bg text-content font-sans antialiased;
    min-height: 100vh;
  }

  h1,
  h2,
  h3 {
    @apply font-serif font-normal;
  }

  ::selection {
    background-color: color-mix(in srgb, var(--color-primary, #977ed4) 30%, transparent);
    color: var(--color-content, #e4e4e7);
  }

  *:focus-visible {
    @apply outline-2 outline-offset-2 outline-primary;
  }

  @media (prefers-reduced-motion: reduce) {
    *,
    *::before,
    *::after {
      animation-duration: 0.01ms;
      animation-iteration-count: 1;
      transition-duration: 0.01ms;
      scroll-behavior: auto;
    }
  }
}

@layer components {
  .stagger-1 {
    animation-delay: 0ms;
  }
  .stagger-2 {
    animation-delay: 60ms;
  }
  .stagger-3 {
    animation-delay: 120ms;
  }
  .stagger-4 {
    animation-delay: 180ms;
  }
  .stagger-5 {
    animation-delay: 240ms;
  }
  .stagger-6 {
    animation-delay: 300ms;
  }
}

